def _extract_interp_only(narrative_text: str) -> str:
    """从 M3 硬编码 narrative 里只取【卦象解读】那段文学部分。

    其他 3 段 (【基础信息】/【卦数附会】/【客观现实】) 由 meihua_qigua.py 自动渲染,
    因为起卦改 CST 后原硬编码数据已失效。
    """
    # 用正则切分: 【卦象解读】 开头到下一个 【】 段为止
    m = re.search(r'【卦象解读】\s*\n(.*?)(?=\n\s*【(?:卦数附会|客观现实)】)', narrative_text, re.DOTALL)
    if m:
        return m.group(1).strip()
    # 兜底: 找不到就返回原文
    return narrative_text.strip()

