def main():
    data = json.loads(MEIHUA.read_text(encoding='utf-8'))
    matches = data['matches']
    written = 0
    for i, m in enumerate(matches, 1):
        qg = m.get('meihua')
        if not qg:
            continue
        # 起卦改 CST 后, 4 段全部从 meihua_qigua.py 自动渲染
        # (M3 之前写的 narrative 文本里包含 UTC 卦象数据, 跟 CST 起卦结果对不上,
        #  全部走模板保证 narrative 与 basic/卦象数据一致)
        llm_narrative = (
            f"【基础信息】\n{qg['basic']}\n\n"
            f"【卦象解读】\n{qg['hexagram_interpretation']}\n\n"
            f"【卦数附会】\n{qg['score_hint']}\n\n"
            f"【客观现实】\n{qg['reality_check']}"
        )
        qg['llm_narrative'] = llm_narrative
        written += 1
    MEIHUA.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding='utf-8')
    print(f"✓ {written}/{len(matches)} 场 narrative 已用 CST 模板重渲染")
    print(f"  写回 {MEIHUA}")


if __name__ == '__main__':
    main()
